INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '98042110-6ac8-4670-8bbd-0e454d553583',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Lock Files — Why package-lock.json Is Your Production Safety Net$escape$,
  $escape$Every `npm install` resolves a dependency graph and writes the result to `package-lock.json`. This file pins the exact version, resolved URL, and integrity hash of every package — including transitive dependencies — so that `npm ci` reproduces that exact graph deterministically on any machine or CI runner. Never delete or gitignore it.

Versioning semantics matter here. `^1.2.3` in `package.json` allows minor/patch bumps, meaning two developers running `npm install` at different times can get different transitive trees. The lock file neutralizes that drift.

For auditing, `npm audit` cross-references your installed tree against the GitHub Advisory Database and returns a severity-ranked report. Use `npm audit --omit=dev` in production pipelines to focus on runtime deps only. `npm audit fix` auto-patches safe semver-compatible upgrades; `--force` escalates to breaking changes — use it deliberately.

For zero-tolerance CI pipelines, fail fast with `npm audit --audit-level=high`. Pair this with `npm ci` (which enforces lock file integrity and errors if it's out of sync with `package.json`) over `npm install` in all automated environments.$escape$,
  $escape$# Reproduce exact locked dependency tree (CI-safe)
npm ci

# Audit runtime deps only, ignore devDependencies
npm audit --omit=dev

# Fail CI pipeline if any high/critical vulnerability exists
npm audit --audit-level=high

# Auto-fix within safe semver bounds
npm audit fix

# Check if lock file is out of sync with package.json
npm install --dry-run$escape$,
