INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3eb3b9f6-3ffb-4d8f-b2cb-0faf77a5313f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Memory Management — How V8's GC Works and Where Leaks Hide$escape$,
  $escape$Node.js runs on V8's generational garbage collector — no ownership model, no compile-time memory safety. V8 splits the heap into young generation (1–8 MB, collected via fast Scavenger minor GC) and old generation (promoted objects, collected via Mark-Sweep-Compact with stop-the-world pauses). Short-lived allocations in the young gen are cheap; objects that survive two minor GCs get promoted and trigger expensive major GCs.

Unlike Rust's borrow checker, leaks in Node.js are invisible until the process OOMs. The three most common culprits: closures capturing large buffers past their useful life, Map/Set caches that never evict, and EventEmitter listeners added without a matching `removeListener` (audit via `emitter.listenerCount()`). `Buffer` and `ArrayBuffer` allocations live outside V8's heap in native memory — tracked separately under `process.memoryUsage().arrayBuffers`, not `heapUsed`.

Snapshot `heapUsed` vs `heapTotal` with `process.memoryUsage()` to detect growth trends. For module-level caches, replace strong Map references with `WeakRef` + `FinalizationRegistry` so V8 can GC entries once no other live reference exists. Use `--expose-gc` in tests to force a collection before asserting memory baselines.$escape$,
  $escape$const before = process.memoryUsage().heapUsed;

// LEAK: strong Map ref — GC can never collect these entries
const leakyCache = new Map();
for (let i = 0; i < 1e5; i++) leakyCache.set(i, Buffer.alloc(100));

const after = process.memoryUsage().heapUsed;
console.log(`Leaked ~${((after - before) / 1024 / 1024).toFixed(1)} MB`);

// SAFE: WeakRef lets GC collect obj when no other strong ref exists
const safeCache = new Map();
function cacheWeak(key, obj) {
  safeCache.set(key, new WeakRef(obj));
}
const retrieved = safeCache.get('key')?.deref(); // undefined if GC'd$escape$,
  $escape$javascript$escape$,
