INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe735632-1276-411d-a3a9-80a32e8d6cdd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Security — Memory Safety, Injection Prevention, and Dependency Scanning$escape$,
  $escape$Node.js doesn't give you memory management foot-guns like C, but you still own the security surface. Three layers matter most.

**Injection prevention:** Never interpolate user input into shell commands. Use `child_process.execFile` with an args array instead of `exec` with template strings — execFile never spawns a shell, so shell metacharacters are inert. For SQL, always use parameterized queries via `pg` or `mysql2`; never concatenate.

**Prototype pollution:** Libraries like `lodash.merge`, `_.set`, and `JSON.parse` on untrusted input can pollute `Object.prototype`. Freeze it early with `Object.freeze(Object.prototype)` or validate deep-merge inputs against a schema using `zod` before touching them.

**Dependency scanning:** Run `npm audit --audit-level=high` in CI and fail the build on high/critical findings. Layer on `socket` CLI or Snyk for supply-chain analysis — `npm audit` only catches known CVEs, not malicious packages that pass CVE checks. Pin lockfile versions with `npm ci` in production builds to prevent floating resolves from silently pulling in a compromised patch.$escape$,
  $escape$// Safe shell execution — no shell spawned, args not interpolated
import { execFile } from 'node:child_process';
import { promisify } from 'node:util';

const execFileAsync = promisify(execFile);

// ❌ Dangerous: exec(`convert ${userFile} output.png`)
// ✅ Safe: args are passed as-is, never interpreted by /bin/sh
const { stdout } = await execFileAsync('convert', [userFile, 'output.png']);

// Freeze prototype to block pollution attacks
Object.freeze(Object.prototype);

// In CI — fail build on high severity vulns
// npm audit --audit-level=high && npm ci$escape$,
  $escape$javascript$escape$,
