INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bbc4f9e0-bfb2-43e4-b18f-a0e541942396',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Horizontal Scaling — Why the Single-Threaded Event Loop Changes Everything$escape$,
  $escape$Node.js runs JavaScript on a single thread per process. That's not a bug — it's the architecture. But it means one CPU core per process, so vertical scaling hits a hard ceiling fast. Horizontal scaling is the answer, but it's not free.

The `cluster` module lets you fork worker processes (one per CPU core), each with its own event loop and V8 heap. The master process load-balances incoming connections across workers using round-robin (default on Linux). Workers share the same port but nothing else — no shared memory, no shared state.

This forces a stateless design by default. Session data, rate-limit counters, and pub/sub state must live in an external store (Redis, Postgres) — not in-process Maps or module-level variables. Any in-process cache is silently per-worker and will diverge.

Beyond `cluster`, `worker_threads` offer true shared memory via `SharedArrayBuffer`, but they don't solve network-level scaling. For that, you still need multiple processes behind a load balancer. PM2's cluster mode wraps this pattern with zero-downtime restarts and built-in metrics, making it production-ready without manual fork management.$escape$,
  $escape$import cluster from 'node:cluster';
import { createServer } from 'node:http';
import { availableParallelism } from 'node:os';

if (cluster.isPrimary) {
  const numCPUs = availableParallelism();
  for (let i = 0; i < numCPUs; i++) cluster.fork();
  cluster.on('exit', (worker) => {
    console.error(`Worker ${worker.process.pid} died — reforking`);
    cluster.fork();
  });
} else {
  createServer((req, res) => res.end(`pid:${process.pid}`)).listen(3000);
}$escape$,
  $escape$javascript$escape$,
