INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '594d462c-9458-4542-89fd-d164807eae64',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js — Where the Event Loop Wins (and Where It Gets You Killed)$escape$,
  $escape$Node.js dominates I/O-bound workloads. Its non-blocking event loop lets a single thread handle thousands of concurrent connections — ideal for REST/GraphQL APIs, WebSocket servers, SSE streams, and BFF layers. `http`, `net`, and `stream` APIs are built around this model. If your bottleneck is waiting — on a DB query, a third-party API, a file read — Node.js handles that with near-zero overhead.

Where it breaks down: CPU-heavy work. A single synchronous computation blocks the entire event loop, freezing every other request. Image processing, PDF generation, crypto mining, ML inference — these will tank your p99 latency. The fix is `worker_threads` for true parallelism, but you're now fighting the language's grain.

Rule of thumb: If your service touches a database and returns JSON, choose Node.js. If it crunches numbers, renders video, or runs a tight loop — reach for Go, Rust, or offload to a sidecar. Mixing both in one process is a trap.$escape$,
  $escape$import { Worker, isMainThread, parentPort } from 'worker_threads';

// BAD: blocks event loop — never do this in request handlers
function blockingHash(data: string) {
  let result = 0;
  for (let i = 0; i < 1e9; i++) result += i; // freezes all requests
  return result;
}

// GOOD: offload CPU work to a worker thread
if (isMainThread) {
  const worker = new Worker(__filename);
  worker.postMessage('compute');
  worker.on('message', (result) => console.log('Done:', result));
} else {
  parentPort?.postMessage(heavyCompute());
}$escape$,
