INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9ecd92ff-47f5-4c85-a700-06b1d40e721c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Node.js Production Monitoring — GC Pauses, Heap Metrics, and Runtime Profiling$escape$,
  $escape$Node.js exposes GC pause data via `perf_hooks`'s `PerformanceObserver` with `entryTypes: ['gc']`. Each entry surfaces `duration` (pause in ms) and `entry.detail.kind` — values like `NODE_PERFORMANCE_GC_MAJOR` (full mark-sweep) and `NODE_PERFORMANCE_GC_MINOR` (scavenge). Major GCs are your p99 latency killers; correlating their timestamps with request traces exposes heap-pressure hotspots instantly.

For heap state, `v8.getHeapStatistics()` is more surgical than `process.memoryUsage()`. It gives you `used_heap_size`, `heap_size_limit`, and `malloced_memory` separately — letting you distinguish V8 heap exhaustion from native addon memory leaks (`external` in `memoryUsage()` tracks C++ objects bound to V8).

In production, wire these into `prom-client`: a `Histogram` for GC pause durations and a `Gauge` for heap utilization ratio. Alert on p95 GC > 50ms or heap utilization > 85%. For CPU profiling without downtime, use `clinic flame` or `0x` — both wrap V8's `--prof` isolate logs into interactive flamegraphs. Avoid `--inspect` in prod; it opens a WebSocket that adds overhead and attack surface.$escape$,
  $escape$const { PerformanceObserver } = require('perf_hooks');
const v8 = require('v8');

const gcObserver = new PerformanceObserver((list) => {
  for (const entry of list.getEntries()) {
    const kind = entry.detail?.kind ?? entry.kind;
    console.log(`GC [kind=${kind}] pause=${entry.duration.toFixed(2)}ms`);
  }
});
gcObserver.observe({ entryTypes: ['gc'] });

setInterval(() => {
  const { used_heap_size, heap_size_limit } = v8.getHeapStatistics();
  const utilization = (used_heap_size / heap_size_limit * 100).toFixed(1);
  console.log(`Heap: ${utilization}% of ${(heap_size_limit / 1e6).toFixed(0)}MB limit`);
}, 10_000);$escape$,
  $escape$javascript$escape$,
